        {/* Tab buttons */}
        <div className="mt-10 flex flex-wrap justify-center gap-2">
          {TABS.map((t, i) => (
            <button
              key={t.label}
              onClick={() => setActive(i)}
              className={`flex items-center gap-2 rounded-full border px-5 py-2 text-sm font-semibold transition ${active === i ? "border-violet-600 bg-violet-600 text-white" : "border-slate-200 bg-white text-slate-600 hover:border-violet-300"}`}
