            <p className="mt-3 text-slate-500">{tab.body}</p>
            <ul className="mt-6 space-y-2">
              {tab.items.map((item) => (
                <li key={item} className="flex items-center gap-3 text-sm text-slate-700">
                  <span className="flex h-5 w-5 shrink-0 items-center justify-center rounded-full bg-violet-100 text-[10px] text-violet-700">✓</span>
                  {item}
                </li>
              ))}
